package com.example.userapp.network;

import com.example.userapp.BuildConfig;
import com.example.userapp.api.UserApiService;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

import okhttp3.Interceptor;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;
import okhttp3.logging.HttpLoggingInterceptor;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class ApiClient {

    private static final int CONNECT_TIMEOUT = 30;
    private static final int READ_TIMEOUT = 30;
    private static final int WRITE_TIMEOUT = 30;

    private static volatile ApiClient instance;
    private final Retrofit retrofit;
    private final UserApiService userApiService;

    private ApiClient() {
        OkHttpClient okHttpClient = buildOkHttpClient();
        retrofit = buildRetrofit(okHttpClient);
        userApiService = retrofit.create(UserApiService.class);
    }

    public static ApiClient getInstance() {
        if (instance == null) {
            synchronized (ApiClient.class) {
                if (instance == null) {
                    instance = new ApiClient();
                }
            }
        }
        return instance;
    }

    public UserApiService getUserApiService() {
        return userApiService;
    }

    public Retrofit getRetrofit() {
        return retrofit;
    }

    private OkHttpClient buildOkHttpClient() {
        OkHttpClient.Builder builder = new OkHttpClient.Builder()
                .connectTimeout(CONNECT_TIMEOUT, TimeUnit.SECONDS)
                .readTimeout(READ_TIMEOUT, TimeUnit.SECONDS)
                .writeTimeout(WRITE_TIMEOUT, TimeUnit.SECONDS)
                .addInterceptor(new AuthInterceptor())
                .addInterceptor(new EnvironmentHeaderInterceptor());

        if (BuildConfig.ENABLE_LOGGING) {
            HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor();
            loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.BODY);
            builder.addInterceptor(loggingInterceptor);
        }

        return builder.build();
    }

    private Retrofit buildRetrofit(OkHttpClient client) {
        return new Retrofit.Builder()
                .baseUrl(BuildConfig.BASE_URL)
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build();
    }

    /**
     * Reset the singleton instance (useful for testing or environment switching at runtime).
     */
    public static void resetInstance() {
        synchronized (ApiClient.class) {
            instance = null;
        }
    }

    private static class AuthInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            Request original = chain.request();
            Request.Builder requestBuilder = original.newBuilder()
                    .header("Accept", "application/json")
                    .header("Content-Type", "application/json");

            // Add auth token if available
            String token = TokenManager.getToken();
            if (token != null && !token.isEmpty()) {
                requestBuilder.header("Authorization", "Bearer " + token);
            }

            return chain.proceed(requestBuilder.build());
        }
    }

    private static class EnvironmentHeaderInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            Request original = chain.request();
            Request modified = original.newBuilder()
                    .header("X-Environment", BuildConfig.ENVIRONMENT)
                    .header("X-App-Version", BuildConfig.VERSION_NAME)
                    .build();
            return chain.proceed(modified);
        }
    }
}


