package com.example.userapp.network;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;

public class Resource<T> {

    public enum Status {
        SUCCESS,
        ERROR,
        LOADING
    }

    @NonNull
    private final Status status;

    @Nullable
    private final T data;

    @Nullable
    private final String message;

    private final int errorCode;

    private Resource(@NonNull Status status, @Nullable T data, @Nullable String message, int errorCode) {
        this.status = status;
        this.data = data;
        this.message = message;
        this.errorCode = errorCode;
    }

    public static <T> Resource<T> success(@Nullable T data) {
        return new Resource<>(Status.SUCCESS, data, null, 0);
    }

    public static <T> Resource<T> error(String message, @Nullable T data) {
        return new Resource<>(Status.ERROR, data, message, 0);
    }

    public static <T> Resource<T> error(String message, int errorCode) {
        return new Resource<>(Status.ERROR, null, message, errorCode);
    }

    public static <T> Resource<T> loading(@Nullable T data) {
        return new Resource<>(Status.LOADING, data, null, 0);
    }

    @NonNull
    public Status getStatus() { return status; }

    @Nullable
    public T getData() { return data; }

    @Nullable
    public String getMessage() { return message; }

    public int getErrorCode() { return errorCode; }

    public boolean isSuccess() { return status == Status.SUCCESS; }
    public boolean isError() { return status == Status.ERROR; }
    public boolean isLoading() { return status == Status.LOADING; }
}


